import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { 
  GiftIcon, 
  TrophyIcon, 
  StarIcon,
  CheckCircleIcon,
  ClockIcon,
  SparklesIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import { useAuth } from '../../contexts/AuthContext';
import { rewardService, VoucherRedemption } from '../../services/rewardService';
import QRCodeModal from '../common/QRCodeModal';

interface Reward {
  id: number;
  userId: number;
  points: number;
  description: string;
  ticketId?: string;
  status: 'PENDING' | 'REDEEMED' | 'EXPIRED';
  createdAt: string;
  redeemedAt?: string;
}

interface Voucher {
  id: number;
  name: string;
  description: string;
  pointsRequired: number;
  discount: string;
  validUntil: string;
  category: string;
  isActive: boolean;
}

const Rewards: React.FC = () => {
  const { user } = useAuth();
  const [rewards, setRewards] = useState<Reward[]>([]);
  const [vouchers, setVouchers] = useState<Voucher[]>([]);
  const [voucherRedemptions, setVoucherRedemptions] = useState<VoucherRedemption[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedVoucher, setSelectedVoucher] = useState<Voucher | null>(null);
  const [showQRModal, setShowQRModal] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [redemptionSuccess, setRedemptionSuccess] = useState(false);

  useEffect(() => {
    const fetchRewardsData = async () => {
      setLoading(true);
      try {
        // Fetch vouchers first (public endpoint)
        const vouchersResponse = await rewardService.getAvailableVouchers();
        console.log('Vouchers response:', vouchersResponse);
        let fetchedVouchers: Voucher[] = [];
        if (vouchersResponse && Array.isArray(vouchersResponse)) {
          fetchedVouchers = vouchersResponse;
        } else if (vouchersResponse && vouchersResponse.success) {
          fetchedVouchers = vouchersResponse.data;
        }
        
        // Sort vouchers: redeemable first, then by points required
        const sortedVouchers = fetchedVouchers.sort((a, b) => {
          const userPoints = user?.points || 0;
          const aRedeemable = userPoints >= a.pointsRequired;
          const bRedeemable = userPoints >= b.pointsRequired;
          
          // If one is redeemable and the other isn't, redeemable comes first
          if (aRedeemable && !bRedeemable) return -1;
          if (!aRedeemable && bRedeemable) return 1;
          
          // If both are redeemable or both are not redeemable, sort by points required
          return a.pointsRequired - b.pointsRequired;
        });
        
        setVouchers(sortedVouchers);
        
        // Try to fetch rewards and redemptions (requires authentication)
        try {
          const [rewardsResponse, redemptionsResponse] = await Promise.all([
            rewardService.getUserRewards(),
            rewardService.getUserVoucherRedemptions()
          ]);
          
          console.log('Rewards response:', rewardsResponse);
          if (rewardsResponse && Array.isArray(rewardsResponse)) {
            setRewards(rewardsResponse);
          } else if (rewardsResponse && rewardsResponse.success) {
            setRewards(rewardsResponse.data);
          }
          
          console.log('Redemptions response:', redemptionsResponse);
          if (redemptionsResponse && Array.isArray(redemptionsResponse)) {
            setVoucherRedemptions(redemptionsResponse);
          } else if (redemptionsResponse && redemptionsResponse.success) {
            setVoucherRedemptions(redemptionsResponse.data);
          }
        } catch (authError) {
          console.log('Rewards/Redemptions require authentication, using empty arrays');
          setRewards([]);
          setVoucherRedemptions([]);
        }
      } catch (error) {
        console.error('Error fetching rewards data:', error);
        // Fallback to mock data if API fails
        setRewards([
          {
            id: 1,
            userId: user?.id || 1,
            points: 50,
            description: 'Ticket SF2024001 resolved',
            ticketId: 'SF2024001',
            status: 'PENDING',
            createdAt: new Date(Date.now() - 86400000).toISOString()
          }
        ]);
        
        setVouchers([
          {
            id: 1,
            name: 'Cafeteria Voucher',
            description: '20% off on any meal',
            pointsRequired: 100,
            discount: '20%',
            validUntil: '2024-12-31',
            category: 'Food',
            isActive: true
          }
        ]);
      }
      
      setLoading(false);
    };

    fetchRewardsData();
  }, [user?.id, user?.points]);

  // Helper function to check if a voucher has been redeemed
  const isVoucherRedeemed = (voucherId: number): boolean => {
    return voucherRedemptions.some(redemption => 
      redemption.voucherId === voucherId && redemption.status === 'ACTIVE'
    );
  };

  // Helper function to get redemption details for a voucher
  const getVoucherRedemption = (voucherId: number): VoucherRedemption | undefined => {
    return voucherRedemptions.find(redemption => 
      redemption.voucherId === voucherId && redemption.status === 'ACTIVE'
    );
  };

  const handleRedeemVoucher = (voucher: Voucher) => {
    setSelectedVoucher(voucher);
    setShowQRModal(true);
  };

  const handleViewVoucher = (voucher: Voucher) => {
    const redemption = getVoucherRedemption(voucher.id);
    if (redemption) {
      // Show redemption details
      alert(`Voucher Details:\n\nRedeemed on: ${new Date(redemption.redeemedAt).toLocaleDateString()}\nPoints used: ${redemption.pointsUsed}\nStatus: ${redemption.status}\nExpires: ${new Date(redemption.expiryDate).toLocaleDateString()}`);
    }
  };

  const confirmRedeem = async () => {
    if (selectedVoucher) {
      setIsProcessing(true);
      try {
        // Check if user is authenticated
        if (!user) {
          alert('Please log in to redeem vouchers.');
          setIsProcessing(false);
          return;
        }
        
        // Make the API call first
        const response = await rewardService.redeemVoucher(selectedVoucher.id);
        console.log('Redemption response:', response);
        
        // Check if response is successful (either wrapped format or direct response)
        if (response && (response.success === true || (response.data && response.data.id))) {
          // Update user points locally
          if (user) {
            user.points = (user.points || 0) - selectedVoucher.pointsRequired;
          }
          
          // Refresh the data
          try {
            const [rewardsResponse, redemptionsResponse] = await Promise.all([
              rewardService.getUserRewards(),
              rewardService.getUserVoucherRedemptions()
            ]);
            
            if (rewardsResponse && Array.isArray(rewardsResponse)) {
              setRewards(rewardsResponse);
            } else if (rewardsResponse && rewardsResponse.success) {
              setRewards(rewardsResponse.data);
            }
            
            if (redemptionsResponse && Array.isArray(redemptionsResponse)) {
              setVoucherRedemptions(redemptionsResponse);
            } else if (redemptionsResponse && redemptionsResponse.success) {
              setVoucherRedemptions(redemptionsResponse.data);
            }
          } catch (authError) {
            console.log('Could not refresh rewards/redemptions (authentication required)');
          }
          
          // Set success state for QR modal
          setRedemptionSuccess(true);
          console.log('Voucher redeemed successfully!');
        } else {
          alert('Failed to redeem voucher: ' + (response.message || 'Unknown error'));
        }
      } catch (error) {
        console.error('Error redeeming voucher:', error);
        if (error instanceof Error && error.message && error.message.includes('401')) {
          alert('Please log in to redeem vouchers.');
        } else {
          alert('Failed to redeem voucher. Please try again.');
        }
      }
      
      setIsProcessing(false);
    }
  };

  const closeQRModal = () => {
    setShowQRModal(false);
    setSelectedVoucher(null);
    setIsProcessing(false);
    setRedemptionSuccess(false);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'PENDING':
        return 'bg-yellow-100 text-yellow-800';
      case 'REDEEMED':
        return 'bg-green-100 text-green-800';
      case 'EXPIRED':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'PENDING':
        return <ClockIcon className="h-4 w-4" />;
      case 'REDEEMED':
        return <CheckCircleIcon className="h-4 w-4" />;
      case 'EXPIRED':
        return <XMarkIcon className="h-4 w-4" />;
      default:
        return <ClockIcon className="h-4 w-4" />;
    }
  };

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Food':
        return 'bg-orange-100 text-orange-800';
      case 'Education':
        return 'bg-blue-100 text-blue-800';
      case 'Services':
        return 'bg-green-100 text-green-800';
      case 'Fitness':
        return 'bg-purple-100 text-purple-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="bg-white rounded-xl shadow-sm p-6">
          <h1 className="text-2xl font-bold text-gray-900 font-poppins">Rewards</h1>
          <p className="text-gray-600 mt-2">Track your points and redeem vouchers</p>
        </div>
        
        <div className="bg-white rounded-xl shadow-sm p-6">
          <div className="animate-pulse space-y-4">
            {[1, 2, 3, 4].map(i => (
              <div key={i} className="h-32 bg-gray-200 rounded-lg"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header with Points Summary */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-gradient-to-r from-primary-500 to-purple-600 rounded-xl shadow-sm p-6 text-white"
      >
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold font-poppins">Rewards Center</h1>
            <p className="mt-2 opacity-90">Track your points and redeem vouchers</p>
          </div>
          <div className="text-right">
            <div className="flex items-center space-x-2">
              <SparklesIcon className="h-8 w-8" />
              <div>
                <p className="text-3xl font-bold">{user?.points || 0}</p>
                <p className="text-sm opacity-90">Total Points</p>
              </div>
            </div>
          </div>
        </div>
      </motion.div>

      {/* Points Progress */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
        className="bg-white rounded-xl shadow-sm p-6"
      >
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900 font-poppins">Points Progress</h2>
          <div className="flex items-center space-x-2">
            <TrophyIcon className="h-5 w-5 text-yellow-500" />
            <span className="text-sm font-medium text-gray-600">Next milestone: 500 points</span>
          </div>
        </div>
        
        <div className="w-full bg-gray-200 rounded-full h-3 mb-2">
          <div
            className="bg-gradient-to-r from-primary-500 to-purple-600 h-3 rounded-full transition-all duration-500"
            style={{ width: `${((user?.points || 0) / 500) * 100}%` }}
          ></div>
        </div>
        <p className="text-sm text-gray-600">
          {user?.points || 0} / 500 points to next milestone
        </p>
      </motion.div>

      {/* Available Vouchers */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
        className="bg-white rounded-xl shadow-sm p-6"
      >
        <h2 className="text-lg font-semibold text-gray-900 font-poppins mb-4">Available Vouchers</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {vouchers.map((voucher, index) => (
            <motion.div
              key={voucher.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 + index * 0.1 }}
              className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow"
            >
              <div className="flex justify-between items-start mb-3">
                <div>
                  <div className="flex items-center space-x-2">
                    <h3 className="font-semibold text-gray-900">{voucher.name}</h3>
                    {isVoucherRedeemed(voucher.id) && (
                      <span className="px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                        Redeemed
                      </span>
                    )}
                  </div>
                  <p className="text-sm text-gray-600 mt-1">{voucher.description}</p>
                </div>
                <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${getCategoryColor(voucher.category)}`}>
                  {voucher.category}
                </span>
              </div>
              
              <div className="flex justify-between items-center">
                <div className="flex items-center space-x-2">
                  <GiftIcon className="h-4 w-4 text-primary-600" />
                  <span className="text-sm font-medium text-gray-700">
                    {voucher.pointsRequired} points
                  </span>
                </div>
                
                {isVoucherRedeemed(voucher.id) ? (
                  <button
                    onClick={() => handleViewVoucher(voucher)}
                    className="px-3 py-1 rounded-lg text-sm font-medium transition-colors bg-green-500 text-white hover:bg-green-600"
                  >
                    View
                  </button>
                ) : (
                  <button
                    onClick={() => handleRedeemVoucher(voucher)}
                    disabled={(user?.points || 0) < voucher.pointsRequired}
                    className={`px-3 py-1 rounded-lg text-sm font-medium transition-colors ${
                      (user?.points || 0) >= voucher.pointsRequired
                        ? 'bg-primary-600 text-white hover:bg-primary-700'
                        : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                    }`}
                  >
                    {(user?.points || 0) >= voucher.pointsRequired ? 'Redeem' : 'Insufficient Points'}
                  </button>
                )}
              </div>
            </motion.div>
          ))}
        </div>
      </motion.div>

      {/* Rewards History */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4 }}
        className="bg-white rounded-xl shadow-sm p-6"
      >
        <h2 className="text-lg font-semibold text-gray-900 font-poppins mb-4">Rewards History</h2>
        <div className="space-y-4">
          {rewards.map((reward, index) => (
            <motion.div
              key={reward.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.5 + index * 0.1 }}
              className="flex items-center justify-between p-4 bg-gray-50 rounded-lg"
            >
              <div className="flex items-center space-x-4">
                <div className="p-2 bg-primary-100 rounded-lg">
                  <StarIcon className="h-5 w-5 text-primary-600" />
                </div>
                <div>
                  <p className="font-medium text-gray-900">+{reward.points} points</p>
                  <p className="text-sm text-gray-600">{reward.description}</p>
                  <p className="text-xs text-gray-500">
                    {new Date(reward.createdAt).toLocaleDateString()}
                  </p>
                </div>
              </div>
              
              {/* Only show status if it's not PENDING */}
              {reward.status !== 'PENDING' && (
                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusColor(reward.status)}`}>
                  {getStatusIcon(reward.status)}
                  <span className="ml-1">{reward.status}</span>
                </span>
              )}
            </motion.div>
          ))}
        </div>
      </motion.div>

      {/* QR Code Modal */}
        {selectedVoucher && (
          <QRCodeModal
            isOpen={showQRModal}
            onClose={closeQRModal}
            voucher={selectedVoucher}
            onConfirm={confirmRedeem}
            isProcessing={isProcessing}
            isSuccess={redemptionSuccess}
          />
        )}
    </div>
  );
};

export default Rewards;
