import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import QRCode from 'qrcode';
import { 
  XMarkIcon, 
  GiftIcon, 
  ClockIcon,
  CheckCircleIcon 
} from '@heroicons/react/24/outline';

interface QRCodeModalProps {
  isOpen: boolean;
  onClose: () => void;
  voucher: {
    id: number;
    name: string;
    description: string;
    discount: string;
    pointsRequired: number;
    category: string;
  };
  onConfirm: () => void;
  isProcessing?: boolean;
  isSuccess?: boolean;
}

const QRCodeModal: React.FC<QRCodeModalProps> = ({
  isOpen,
  onClose,
  voucher,
  onConfirm,
  isProcessing = false,
  isSuccess = false
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [countdown, setCountdown] = useState(5);
  const [isConfirmed, setIsConfirmed] = useState(false);

  // Generate QR code
  useEffect(() => {
    if (isOpen && canvasRef.current) {
      const voucherData = {
        id: voucher.id,
        name: voucher.name,
        discount: voucher.discount,
        pointsRequired: voucher.pointsRequired,
        timestamp: new Date().toISOString(),
        code: `SF${voucher.id}${Date.now()}`
      };

      const canvasSize = window.innerWidth < 640 ? 150 : 200;
      QRCode.toCanvas(canvasRef.current, JSON.stringify(voucherData), {
        width: canvasSize,
        margin: 2,
        color: {
          dark: '#000000',
          light: '#FFFFFF'
        }
      }).catch(console.error);
    }
  }, [isOpen, voucher]);

  // Countdown timer
  useEffect(() => {
    if (isOpen && !isConfirmed) {
      const timer = setInterval(() => {
        setCountdown((prev) => {
          if (prev <= 1) {
            setIsConfirmed(true);
            onConfirm();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);

      return () => clearInterval(timer);
    }
  }, [isOpen, isConfirmed, onConfirm]);

  // Reset state when modal closes
  useEffect(() => {
    if (!isOpen) {
      setCountdown(5);
      setIsConfirmed(false);
    }
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="bg-white rounded-xl p-4 sm:p-6 max-w-sm sm:max-w-md w-full mx-2 sm:mx-4 relative max-h-[90vh] overflow-y-auto"
        >
          {/* Close button */}
          <button
            onClick={onClose}
            className="absolute top-4 right-4 p-2 hover:bg-gray-100 rounded-lg transition-colors"
            disabled={isProcessing}
          >
            <XMarkIcon className="h-5 w-5 text-gray-500" />
          </button>

          <div className="text-center">
            {/* Header */}
            <div className="mb-6">
              <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-green-100 mb-4">
                <GiftIcon className="h-8 w-8 text-green-600" />
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-2">
                Voucher Redeemed!
              </h3>
              <p className="text-sm text-gray-600">
                Show this QR code to redeem your discount
              </p>
            </div>

            {/* Voucher Details */}
            <div className="bg-gray-50 rounded-lg p-4 mb-6">
              <h4 className="font-semibold text-gray-900 mb-2">{voucher.name}</h4>
              <p className="text-sm text-gray-600 mb-3">{voucher.description}</p>
              
              <div className="flex justify-between items-center text-sm">
                <span className="text-gray-600">Discount:</span>
                <span className="font-semibold text-green-600">{voucher.discount}</span>
              </div>
              
              <div className="flex justify-between items-center text-sm mt-1">
                <span className="text-gray-600">Category:</span>
                <span className="font-medium text-gray-900">{voucher.category}</span>
              </div>
              
              <div className="flex justify-between items-center text-sm mt-1">
                <span className="text-gray-600">Points Used:</span>
                <span className="font-semibold text-red-600">{voucher.pointsRequired}</span>
              </div>
            </div>

            {/* QR Code */}
            <div className="mb-4 sm:mb-6">
              <div className="flex justify-center">
                <canvas
                  ref={canvasRef}
                  className="border-2 border-gray-200 rounded-lg max-w-full h-auto"
                />
              </div>
              <p className="text-xs text-gray-500 mt-2 text-center">
                Valid for 30 days from redemption
              </p>
            </div>

            {/* Countdown or Confirmation */}
            <div className="mb-6">
              {!isConfirmed ? (
                <div className="flex items-center justify-center space-x-2 text-orange-600">
                  <ClockIcon className="h-5 w-5 animate-pulse" />
                  <span className="font-medium">
                    Processing in {countdown}s...
                  </span>
                </div>
              ) : isSuccess ? (
                <div className="flex items-center justify-center space-x-2 text-green-600">
                  <CheckCircleIcon className="h-5 w-5" />
                  <span className="font-medium">
                    Points deducted successfully!
                  </span>
                </div>
              ) : (
                <div className="flex items-center justify-center space-x-2 text-gray-600">
                  <ClockIcon className="h-5 w-5" />
                  <span className="font-medium">
                    Processing...
                  </span>
                </div>
              )}
            </div>

            {/* Instructions */}
            <div className="text-left bg-blue-50 rounded-lg p-3 sm:p-4">
              <h5 className="font-medium text-blue-900 mb-2 text-sm sm:text-base">How to use:</h5>
              <ul className="text-xs sm:text-sm text-blue-800 space-y-1">
                <li>• Show this QR code to the merchant</li>
                <li>• Present your student ID if required</li>
                <li>• Enjoy your {voucher.discount} discount!</li>
              </ul>
            </div>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

export default QRCodeModal;
